class Solution {
public:
    bool checkRecord(string s) {
        int absences = 0;
        int lateStreak = 0;

        for (char c : s) {
            if (c == 'A') absences++;
            if (c == 'L') lateStreak++;
            else lateStreak = 0;

            if (absences >= 2 || lateStreak >= 3) return false;
        }

        return true;
    }
};
```
